import { Building2, Command, MessageSquare, Moon, Sun, Sparkles } from "lucide-react";
import { useEffect, useState } from "react";
import { cn } from "../lib/cn";

type Props = {
  properties: string[];
  lie: string;
  onLieChange: (v: string) => void;
  onOpenPalette: () => void;
  askCollapsed: boolean;
  onToggleAsk: () => void;
};

export function TopBar({
  properties,
  lie,
  onLieChange,
  onOpenPalette,
  askCollapsed,
  onToggleAsk,
}: Props) {
  const [theme, setTheme] = useState<"dark" | "light">(() => {
    if (typeof window === "undefined") return "dark";
    const stored = window.localStorage.getItem("theme");
    if (stored === "light" || stored === "dark") return stored;
    return window.matchMedia("(prefers-color-scheme: light)").matches ? "light" : "dark";
  });

  useEffect(() => {
    const root = document.documentElement;
    root.classList.toggle("dark", theme === "dark");
    root.classList.toggle("light", theme === "light");
    window.localStorage.setItem("theme", theme);
  }, [theme]);

  return (
    <header className="glass sticky top-0 z-40 flex h-12 items-center justify-between gap-4 border-b border-[var(--color-border)] px-4">
      <div className="flex items-center gap-3">
        <div className="flex items-center gap-2">
          <div className="grid h-6 w-6 place-items-center rounded-md bg-[var(--color-accent)] text-[#0b0b0a]">
            <Building2 className="h-3.5 w-3.5" strokeWidth={2.5} />
          </div>
          <span className="font-display text-[15px] font-medium tracking-tight text-[var(--color-ink-50)]">
            Buena
          </span>
          <span className="text-[11px] uppercase tracking-[0.18em] text-[var(--color-fg-muted)]">
            Context
          </span>
        </div>

        <span className="h-4 w-px bg-[var(--color-border)]" aria-hidden />

        <div className="flex items-center gap-1.5">
          <span className="text-[11px] uppercase tracking-[0.18em] text-[var(--color-fg-dim)]">
            Property
          </span>
          <div className="relative">
            <select
              value={lie}
              onChange={(e) => onLieChange(e.target.value)}
              disabled={properties.length === 0}
              className={cn(
                "h-7 cursor-pointer appearance-none rounded-md border border-[var(--color-border-2)] bg-[var(--color-surface)]",
                "px-2.5 pr-7 font-mono text-[12px] font-medium text-[var(--color-fg)]",
                "outline-none transition-colors hover:border-[var(--color-accent-dim)] focus:border-[var(--color-accent)]",
              )}
            >
              {properties.map((p) => (
                <option key={p} value={p}>
                  {p}
                </option>
              ))}
            </select>
            <span className="pointer-events-none absolute right-2 top-1/2 -translate-y-1/2 text-[var(--color-fg-muted)]">
              <svg width="8" height="6" viewBox="0 0 8 6" fill="none">
                <path
                  d="M1 1.5L4 4.5L7 1.5"
                  stroke="currentColor"
                  strokeWidth="1.4"
                  strokeLinecap="round"
                />
              </svg>
            </span>
          </div>
        </div>
      </div>

      <div className="flex items-center gap-2">
        <button
          onClick={onOpenPalette}
          className={cn(
            "group flex h-7 items-center gap-2 rounded-md border border-[var(--color-border-2)]",
            "bg-[var(--color-surface)] px-2.5 text-[12px] text-[var(--color-fg-muted)]",
            "transition-colors hover:border-[var(--color-accent-dim)] hover:text-[var(--color-fg)]",
          )}
        >
          <Sparkles className="h-3 w-3 text-[var(--color-accent)]" />
          <span>Jump to file</span>
          <kbd className="ml-1 flex items-center gap-0.5 rounded border border-[var(--color-border)] bg-[var(--color-bg)] px-1 py-0 font-mono text-[10px] tracking-tight text-[var(--color-fg-dim)]">
            <Command className="h-2.5 w-2.5" />K
          </kbd>
        </button>

        <button
          onClick={onToggleAsk}
          aria-label={askCollapsed ? "Open Ask panel" : "Close Ask panel"}
          title={askCollapsed ? "Open Ask panel" : "Close Ask panel"}
          className={cn(
            "grid h-7 w-7 place-items-center rounded-md border transition-colors",
            askCollapsed
              ? "border-[var(--color-border-2)] bg-[var(--color-surface)] text-[var(--color-fg-muted)] hover:border-[var(--color-accent-dim)] hover:text-[var(--color-fg)]"
              : "border-[var(--color-accent-dim)] bg-[var(--color-surface)] text-[var(--color-accent)]",
          )}
        >
          <MessageSquare className="h-3.5 w-3.5" />
        </button>

        <button
          onClick={() => setTheme((t) => (t === "dark" ? "light" : "dark"))}
          aria-label="Toggle theme"
          className={cn(
            "grid h-7 w-7 place-items-center rounded-md border border-[var(--color-border-2)]",
            "bg-[var(--color-surface)] text-[var(--color-fg-muted)]",
            "transition-colors hover:border-[var(--color-accent-dim)] hover:text-[var(--color-fg)]",
          )}
        >
          {theme === "dark" ? (
            <Sun className="h-3.5 w-3.5" />
