          <TreeSkeleton />
        )}
      </div>
    </aside>
  );

  return (
    <div className="flex h-screen flex-col overflow-hidden">
      <TopBar
        onOpenPalette={() => setPaletteOpen(true)}
        askActive={askButtonActive}
        onToggleAsk={toggleAsk}
        treeActive={treeButtonActive}
        onToggleTree={toggleTree}
      />

      <div className="min-h-0 flex-1">
        {isMobile ? (
          <main className="flex h-full min-w-0 flex-col">
            <div className="min-h-0 flex-1">
              <Viewer
                path={path}
                content={content}
                loading={loading}
                error={error}
              />
            </div>
          </main>
        ) : (
          <Group orientation="horizontal" className="h-full">
            <Panel
              panelRef={treePanelRef}
              defaultSize="20%"
              minSize="14%"
              maxSize="32%"
              collapsible
              collapsedSize="0%"
              onResize={(size) => setTreeCollapsed(size.asPercentage < 1)}
              className="tree-panel overflow-hidden"
            >
              {!treeCollapsed && treeSidebar}
            </Panel>

            <Separator />

            <Panel defaultSize="56%" minSize="32%" className="overflow-hidden">
              <main className="flex h-full min-w-0 flex-col">
                <div className="min-h-0 flex-1">
                  <Viewer
                    path={path}
                    content={content}
                    loading={loading}
                    error={error}
                  />
                </div>
              </main>
            </Panel>

            <Separator />

            <Panel
              panelRef={askPanelRef}
              defaultSize="24%"
              minSize="18%"
              maxSize="42%"
              collapsible
              collapsedSize="0%"
              onResize={(size) => setAskCollapsed(size.asPercentage < 1)}
              className="ask-panel overflow-hidden"
            >
              {!askCollapsed && <Query lie={lie} onResolved={selectPath} />}
            </Panel>
          </Group>
        )}
      </div>

      {isMobile && (mobileTreeOpen || mobileAskOpen) && (
        <button
          aria-label="Close panel"
          onClick={() => {
            setMobileTreeOpen(false);
            setMobileAskOpen(false);
          }}
          className="fixed inset-0 z-40 bg-black/60 backdrop-blur-sm"
        />
      )}

      {isMobile && (
        <div
          className={`fixed inset-y-0 left-0 z-50 w-[min(82vw,320px)] transform bg-[var(--color-bg)] shadow-2xl transition-transform duration-200 ${
